#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
const ll inf=1e18;
ll n,m,q,a[N],b[N],amn[N][25],amx[N][25],bmn[N][25],bmx[N][25],azmn[N][25],afmx[N][25];
int main()
{
	cin>>n>>m>>q;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		amn[i][0]=amx[i][0]=a[i];
		afmx[i][0]=(a[i]<0)?a[i]:(-inf);
		azmn[i][0]=(a[i]>=0)?a[i]:inf;
	}
	for(int i=1;i<=m;i++)
	{
		cin>>b[i];
		bmx[i][0]=bmn[i][0]=b[i];
	}
	for(int i=1;i<=log2(n);i++)
	{
		for(int j=1;j+(1<<i)-1<=n;j++)
		{
			int tmp=j+(1<<(i-1));
			amx[j][i]=max(amx[j][i-1],amx[tmp][i-1]);
			afmx[j][i]=max(afmx[j][i-1],afmx[tmp][i-1]);
			amn[j][i]=min(amn[j][i-1],amn[tmp][i-1]);
			azmn[j][i]=min(azmn[j][i-1],azmn[tmp][i-1]);
		}
	}
	for(int i=1;i<=log2(m);i++)
	{
		for(int j=1;j+(1<<i)-1<=m;j++)
		{
			int tmp=j+(1<<(i-1));
			bmx[j][i]=max(bmx[j][i-1],bmx[tmp][i-1]);
			bmn[j][i]=min(bmn[j][i-1],bmn[tmp][i-1]);
		}
	}
	while(q--) 
	{
		int la,ra,lb,rb;
		cin>>la>>ra>>lb>>rb;
		ll len1=log2(ra-la+1),len2=log2(rb-lb+1);
		ll tmp1=ra-(1<<len1)+1,tmp2=rb-(1<<len2)+1;
		ll amax=max(amx[la][len1],amx[tmp1][len1]);
		ll amin=min(amn[la][len1],amn[tmp1][len1]);
		ll afmax=max(afmx[la][len1],afmx[tmp1][len1]);
		ll azmin=min(azmn[la][len1],azmn[tmp1][len1]);
		ll bmax=max(bmx[lb][len2],bmx[tmp2][len2]);
		ll bmin=min(bmn[lb][len2],bmn[tmp2][len2]);
//		dbg(amax);
//		dbg(amin);
//		dbg(bmax);
//		dbg(bmin);
//		dbg(afmax);
//		dbg(azmin);
		ll ans=-inf;
		ans=max(amax*(amax>=0?bmin:bmax),amin*(amin>=0?bmin:bmax));
		if(afmax!=-inf) ans=max(ans,afmax*(afmax>=0?bmin:bmax));
		if(azmin!=inf) ans=max(ans,azmin*(azmin>=0?bmin:bmax));
		cout<<ans<<"\n";
	}
	return 0;
}
